import { lazy, Suspense, useEffect } from 'react';
import { BrowserRouter, Routes, Route, Navigate, useLocation } from 'react-router-dom';
import { QueryClient, QueryClientProvider } from '@tanstack/react-query';
import { Toaster } from 'react-hot-toast';
import { AnimatePresence } from 'framer-motion';
import { useUserStore } from './store/userStore.js';
import { useMe } from './queries/auth.queries.js';
import Navbar from './components/common/Navbar.jsx';
import ErrorBoundary from './components/common/ErrorBoundary.jsx';
import Loader from './components/common/Loader.jsx';

const Landing = lazy(() => import('./pages/Landing.jsx'));
const Login = lazy(() => import('./pages/Login.jsx'));
const Register = lazy(() => import('./pages/Register.jsx'));
const Setup = lazy(() => import('./pages/Setup.jsx'));
const InterviewRoom = lazy(() => import('./pages/InterviewRoom.jsx'));
const Results = lazy(() => import('./pages/Results.jsx'));
const Dashboard = lazy(() => import('./pages/Dashboard.jsx'));
const Profile = lazy(() => import('./pages/Profile.jsx'));

const queryClient = new QueryClient({
  defaultOptions: {
    queries: { retry: 1, refetchOnWindowFocus: false },
  },
});

function ProtectedRoute({ children }) {
  const { isAuthenticated, isLoading } = useUserStore();
  if (isLoading) return <Loader fullScreen text="Checking auth..." />;
  if (!isAuthenticated) return <Navigate to="/login" replace />;
  return children;
}

function GuestRoute({ children }) {
  const { isAuthenticated, isLoading } = useUserStore();
  if (isLoading) return <Loader fullScreen text="Checking auth..." />;
  if (isAuthenticated) return <Navigate to="/dashboard" replace />;
  return children;
}

function AuthInitializer({ children }) {
  const { isLoading } = useMe();
  if (isLoading) return <Loader fullScreen text="Initializing..." />;
  return children;
}

function AnimatedRoutes() {
  const location = useLocation();
  return (
    <AnimatePresence mode="wait">
      <Suspense fallback={<Loader fullScreen />}>
        <Routes location={location} key={location.pathname}>
          <Route path="/" element={<Landing />} />
          <Route path="/login" element={<GuestRoute><Login /></GuestRoute>} />
          <Route path="/register" element={<GuestRoute><Register /></GuestRoute>} />
          <Route path="/setup" element={<ProtectedRoute><Setup /></ProtectedRoute>} />
          <Route path="/interview/:id" element={<ProtectedRoute><InterviewRoom /></ProtectedRoute>} />
          <Route path="/results/:sessionId" element={<ProtectedRoute><Results /></ProtectedRoute>} />
          <Route path="/dashboard" element={<ProtectedRoute><Dashboard /></ProtectedRoute>} />
          <Route path="/profile" element={<ProtectedRoute><Profile /></ProtectedRoute>} />
          <Route path="*" element={<Navigate to="/" replace />} />
        </Routes>
      </Suspense>
    </AnimatePresence>
  );
}

export default function App() {
  return (
    <QueryClientProvider client={queryClient}>
      <ErrorBoundary>
        <BrowserRouter>
          <AuthInitializer>
            <Navbar />
            <AnimatedRoutes />
          </AuthInitializer>
        </BrowserRouter>
        <Toaster
          position="top-right"
          toastOptions={{
            style: {
              background: '#1A1A2E',
              color: '#F1F5F9',
              border: '1px solid #2D2D44',
              borderRadius: '12px',
              fontSize: '14px',
            },
          }}
        />
      </ErrorBoundary>
    </QueryClientProvider>
  );
}

import { motion } from 'framer-motion';

export default function Loader({ text = 'Loading...', fullScreen = false }) {
  const content = (
    <div className="flex flex-col items-center gap-4">
      <div className="flex gap-1.5">
        {[0, 1, 2].map((i) => (
          <motion.div
            key={i}
            className="w-3 h-3 rounded-full bg-primary"
            animate={{ y: [-8, 8, -8], opacity: [0.4, 1, 0.4] }}
            transition={{ duration: 1, repeat: Infinity, delay: i * 0.15, ease: 'easeInOut' }}
          />
        ))}
      </div>
      <p className="text-sm text-text-muted">{text}</p>
    </div>
  );

  if (fullScreen) {
    return <div className="fixed inset-0 bg-bg-base flex items-center justify-center z-50">{content}</div>;
  }
  return <div className="flex items-center justify-center py-20">{content}</div>;
}

import { Link, useNavigate } from 'react-router-dom';
import { motion } from 'framer-motion';
import { useUserStore } from '../../store/userStore.js';
import { useLogout } from '../../queries/auth.queries.js';
import { getInitials } from '../../lib/utils.js';

export default function Navbar() {
  const { user, isAuthenticated } = useUserStore();
  const logout = useLogout();
  const navigate = useNavigate();

  const handleLogout = () => {
    logout.mutate();
    navigate('/');
  };

  return (
    <motion.nav
      initial={{ y: -20, opacity: 0 }}
      animate={{ y: 0, opacity: 1 }}
      className="fixed top-0 left-0 right-0 z-50 glass"
    >
      <div className="max-w-7xl mx-auto px-4 sm:px-6 lg:px-8">
        <div className="flex items-center justify-between h-16">
          <Link to="/" className="flex items-center gap-2">
            <div className="w-8 h-8 rounded-lg bg-linear-gradient-to-br from-primary to-[#A78BFA] flex items-center justify-center text-white font-bold text-sm">AI</div>
            <span className="text-lg font-bold gradient-text hidden sm:block">MockPrep</span>
          </Link>

          <div className="flex items-center gap-3">
            {isAuthenticated ? (
              <>
                <Link to="/dashboard" className="text-sm text-text-secondary hover:text-text-primary transition-colors px-3 py-1.5">Dashboard</Link>
                <Link to="/setup" className="text-sm bg-primary hover:bg-primary-hover text-white px-4 py-1.5 rounded-lg transition-colors">New Interview</Link>
                <div className="relative group">
                  <button className="w-8 h-8 rounded-full bg-bg-card border border-border flex items-center justify-center text-xs font-semibold text-primary-light">
                    {getInitials(user?.name)}
                  </button>
                  <div className="absolute right-0 top-10 w-48 bg-bg-card border border-border rounded-xl shadow-xl opacity-0 invisible group-hover:opacity-100 group-hover:visible transition-all duration-200 py-2">
                    <div className="px-4 py-2 border-b border-border">
                      <p className="text-sm font-medium">{user?.name}</p>
                      <p className="text-xs text-text-muted">{user?.email}</p>
                    </div>
                    <Link to="/profile" className="block px-4 py-2 text-sm hover:bg-bg-elevated transition-colors">Profile</Link>
                    <button onClick={handleLogout} className="w-full text-left px-4 py-2 text-sm text-danger hover:bg-bg-elevated transition-colors">Logout</button>
                  </div>
                </div>
              </>
            ) : (
              <>
                <Link to="/login" className="text-sm text-text-secondary hover:text-text-primary transition-colors px-3 py-1.5">Login</Link>
                <Link to="/register" className="text-sm bg-primary hover:bg-primary-hover text-white px-4 py-1.5 rounded-lg transition-colors btn-glow">Get Started</Link>
              </>
            )}
          </div>
        </div>
      </div>
    </motion.nav>
  );
}

import { Link } from 'react-router-dom';
import { motion } from 'framer-motion';
import { staggerContainer, staggerItem } from '../../animations/variants.js';
import { STATUS_COLORS, ROUND_LABELS } from '../../lib/constants.js';
import { timeAgo, formatScore } from '../../lib/utils.js';

export default function SessionHistory({ sessions = [] }) {
  if (sessions.length === 0) {
    return <div className="text-center text-sm text-text-muted py-8">No interview sessions yet. Start your first one!</div>;
  }

  return (
    <motion.div variants={staggerContainer} initial="initial" animate="animate" className="space-y-3">
      {sessions.map((s) => (
        <motion.div key={s.id} variants={staggerItem}>
          <Link to={s.status === 'COMPLETED' ? `/results/${s.id}` : `/interview/${s.id}`} className="block bg-bg-card rounded-xl border border-border p-4 hover:border-primary/50 transition-colors">
            <div className="flex items-center justify-between">
              <div>
                <div className="flex items-center gap-2">
                  <span className="text-sm font-medium">{s.level?.replace('_', '-')}</span>
                  <span className="text-xs text-text-muted">•</span>
                  <span className="text-xs text-text-muted">{s.role?.replace('_', ' ')}</span>
                  <span className="text-xs text-text-muted">•</span>
                  <span className="text-xs text-text-muted">{s.companyType}</span>
                </div>
                <p className="text-xs text-text-muted mt-1">{timeAgo(s.startedAt)}</p>
              </div>
              <div className="text-right">
                <span className="text-xs px-2 py-0.5 rounded-full font-medium" style={{ backgroundColor: `${STATUS_COLORS[s.status]}20`, color: STATUS_COLORS[s.status] }}>{s.status?.replace('_', ' ')}</span>
                {s.finalScore !== null && <p className="text-lg font-bold mt-1" style={{ color: STATUS_COLORS.COMPLETED }}>{Math.round(s.finalScore)}</p>}
              </div>
            </div>
          </Link>
        </motion.div>
      ))}
    </motion.div>
  );
}

import { motion } from 'framer-motion';
import { staggerItem } from '../../animations/variants.js';

export default function WeakAreaCard({ areas = [], type = 'weak' }) {
  const isWeak = type === 'weak';
  return (
    <div className="bg-bg-card rounded-xl border border-border p-4">
      <h3 className="text-sm font-semibold mb-3">{isWeak ? '⚠️ Weak Areas' : '💪 Strong Areas'}</h3>
      {areas.length === 0 ? (
        <p className="text-xs text-text-muted">Complete more interviews to identify {isWeak ? 'weak' : 'strong'} areas</p>
      ) : (
        <div className="flex flex-wrap gap-2">
          {areas.map((area, i) => (
            <motion.span key={area} variants={staggerItem} className={`text-xs px-3 py-1.5 rounded-full capitalize ${isWeak ? 'bg-danger/10 text-danger-light' : 'bg-success/10 text-success-light'}`}>{area.replace(/([A-Z])/g, ' $1').trim()}</motion.span>
          ))}
        </div>
      )}
    </div>
  );
}

import { motion } from 'framer-motion';

export default function AITypingIndicator({ message = 'AI is evaluating your answer...' }) {
  return (
    <motion.div initial={{ opacity: 0, y: 10 }} animate={{ opacity: 1, y: 0 }} className="flex items-center gap-3 p-4 bg-bg-card rounded-xl border border-border/30">
      <div className="flex gap-1">
        {[0, 1, 2].map((i) => (
          <motion.div key={i} className="w-2 h-2 rounded-full bg-primary" animate={{ y: [-3, 3, -3], opacity: [0.4, 1, 0.4] }} transition={{ duration: 0.8, repeat: Infinity, delay: i * 0.2 }} />
        ))}
      </div>
      <span className="text-sm text-text-secondary">{message}</span>
    </motion.div>
  );
}

import { useState } from 'react';
import { motion, AnimatePresence } from 'framer-motion';
import { expandVariants } from '../../animations/variants.js';

export default function HintPanel({ hints = [], hintsUsed = 0, maxHints = 3, onRequestHint, loading }) {
  const [expanded, setExpanded] = useState(false);
  const available = Math.min(maxHints, hints.length) - hintsUsed;

  return (
    <div className="bg-bg-card rounded-xl border border-border overflow-hidden">
      <button
        onClick={() => { if (available > 0 && !loading) { setExpanded(!expanded); if (!expanded && hintsUsed < hints.length) onRequestHint?.(); } }}
        className="w-full flex items-center justify-between px-4 py-3 hover:bg-bg-elevated transition-colors"
        disabled={available <= 0}
      >
        <span className="text-sm flex items-center gap-2">
          💡 <span className="font-medium">Hints</span>
          <span className="text-xs text-text-muted">({available} remaining)</span>
        </span>
        <motion.span animate={{ rotate: expanded ? 180 : 0 }} className="text-text-muted">▼</motion.span>
      </button>

      <AnimatePresence>
        {expanded && (
          <motion.div variants={expandVariants} initial="collapsed" animate="expanded" exit="collapsed" className="overflow-hidden">
            <div className="px-4 pb-4 space-y-2">
              {hints.slice(0, hintsUsed).map((hint, i) => (
                <div key={i} className="text-sm p-3 rounded-lg bg-bg-elevated border-l-2 border-warning">
                  <span className="text-xs text-warning font-medium">Hint {i + 1}:</span>
                  <p className="mt-1 text-text-secondary">{hint}</p>
                </div>
              ))}
              {loading && <div className="skeleton h-16 w-full" />}
            </div>
          </motion.div>
        )}
      </AnimatePresence>
    </div>
  );
}

import { motion } from 'framer-motion';
import { getScoreColor } from '../../lib/utils.js';

export default function LiveFeedbackPanel({ evaluation }) {
  if (!evaluation) return null;

  const score = evaluation.totalScore || 0;
  const color = getScoreColor(score);

  return (
    <motion.div initial={{ opacity: 0, y: 20 }} animate={{ opacity: 1, y: 0 }} className="bg-bg-card rounded-xl border border-border p-6 space-y-4">
      <div className="flex items-center justify-between">
        <h3 className="text-sm font-semibold">AI Evaluation</h3>
        <div className="flex items-center gap-2">
          <span className="text-2xl font-bold" style={{ color }}>{score}</span>
          <span className="text-sm text-text-muted">/ 100</span>
        </div>
      </div>

      {evaluation.breakdown && (
        <div className="grid grid-cols-2 gap-2">
          {Object.entries(evaluation.breakdown).map(([key, val]) => (
            <div key={key} className="p-2 bg-bg-surface rounded-lg">
              <p className="text-xs text-text-muted capitalize">{key.replace(/([A-Z])/g, ' $1').trim()}</p>
              <p className="text-sm font-semibold" style={{ color: getScoreColor((val / 40) * 100) }}>{val}</p>
            </div>
          ))}
        </div>
      )}

      {evaluation.verdict && (
        <div className={`text-sm font-medium px-3 py-1.5 rounded-lg inline-block ${evaluation.verdict === 'Excellent' || evaluation.verdict === 'Strong' ? 'bg-success/20 text-success' : evaluation.verdict === 'Good' ? 'bg-primary/20 text-primary-light' : evaluation.verdict === 'Average' ? 'bg-warning/20 text-warning' : 'bg-danger/20 text-danger'}`}>
          {evaluation.verdict}
        </div>
      )}

      {evaluation.positiveFeedback && <p className="text-sm text-success-light">✓ {evaluation.positiveFeedback}</p>}
      {evaluation.improvements?.length > 0 && (
        <div>
          <p className="text-xs text-text-muted mb-1">Improvements:</p>
          {evaluation.improvements.map((imp, i) => <p key={i} className="text-sm text-text-secondary">• {imp}</p>)}
        </div>
      )}
    </motion.div>
  );
}

import { motion } from 'framer-motion';
import { cardVariants } from '../../animations/variants.js';
import { ROUND_LABELS } from '../../lib/constants.js';

export default function QuestionCard({ question, questionNumber, totalQuestions, roundType }) {
  const difficulty = question?.metadata?.difficulty || 'Medium';
  const topic = question?.metadata?.topic || '';
  const diffColor = difficulty === 'Easy' ? 'var(--color-success)' : difficulty === 'Hard' ? 'var(--color-danger)' : 'var(--color-warning)';

  return (
    <motion.div variants={cardVariants} initial="initial" animate="animate" className="bg-bg-card rounded-xl border border-border p-6">
      <div className="flex items-center gap-2 mb-4 flex-wrap">
        <span className="text-xs px-2.5 py-1 rounded-full bg-primary/20 text-primary-light font-medium">{ROUND_LABELS[roundType] || roundType}</span>
        <span className="text-xs px-2.5 py-1 rounded-full font-medium" style={{ backgroundColor: `${diffColor}20`, color: diffColor }}>{difficulty}</span>
        {topic && <span className="text-xs px-2.5 py-1 rounded-full bg-bg-elevated text-text-muted">{topic}</span>}
        <span className="ml-auto text-xs text-text-muted">Q{questionNumber}/{totalQuestions}</span>
      </div>
      <div className="prose prose-invert max-w-none">
        <pre className="whitespace-pre-wrap text-sm leading-relaxed text-text-primary font-sans">{question?.content}</pre>
      </div>
    </motion.div>
  );
}

import { motion, AnimatePresence } from 'framer-motion';
import { ROUND_LABELS } from '../../lib/constants.js';
import { roundTransitionVariants } from '../../animations/variants.js';

export default function RoundTransition({ roundType, roundNumber, totalRounds, show, onComplete }) {
  return (
    <AnimatePresence>
      {show && (
        <motion.div variants={roundTransitionVariants} initial="initial" animate="animate" exit="exit" onAnimationComplete={() => setTimeout(onComplete, 1500)} className="fixed inset-0 z-50 bg-bg-base/95 backdrop-blur-lg flex items-center justify-center">
          <div className="text-center">
            <motion.div initial={{ scale: 0 }} animate={{ scale: 1 }} transition={{ type: 'spring', stiffness: 200, delay: 0.2 }} className="w-20 h-20 rounded-2xl bg-linear-to-br from-primary to-[#A78BFA] flex items-center justify-center text-3xl mx-auto mb-6">
              {roundNumber}
            </motion.div>
            <motion.h2 initial={{ opacity: 0, y: 20 }} animate={{ opacity: 1, y: 0 }} transition={{ delay: 0.4 }} className="text-3xl font-bold mb-2">{ROUND_LABELS[roundType] || roundType}</motion.h2>
            <motion.p initial={{ opacity: 0 }} animate={{ opacity: 1 }} transition={{ delay: 0.6 }} className="text-text-muted">Round {roundNumber} of {totalRounds}</motion.p>
          </div>
        </motion.div>
      )}
    </AnimatePresence>
  );
}

import { motion } from 'framer-motion';
import { formatTime } from '../../lib/utils.js';

export default function TimerBar({ timeRemaining, totalTime }) {
  const pct = totalTime > 0 ? (timeRemaining / totalTime) * 100 : 0;
  const color = pct > 50 ? 'var(--color-success)' : pct > 20 ? 'var(--color-warning)' : 'var(--color-danger)';

  return (
    <div className="w-full">
      <div className="flex justify-between items-center mb-1">
        <span className="text-xs text-text-muted">Time Remaining</span>
        <span className="text-sm font-mono font-bold" style={{ color }}>{formatTime(timeRemaining)}</span>
      </div>
      <div className="h-2 bg-bg-elevated rounded-full overflow-hidden">
        <motion.div
          className="h-full rounded-full"
          style={{ backgroundColor: color }}
          animate={{ width: `${pct}%` }}
          transition={{ duration: 0.5, ease: 'linear' }}
        />
      </div>
    </div>
  );
}

import { motion } from 'framer-motion';
import { useVoice } from '../../hooks/useVoice.js';
import { useEffect } from 'react';

export default function VoiceRecorder({ onTranscriptChange }) {
  const { isRecording, transcript, isSupported, startRecording, stopRecording, setTranscript } = useVoice();

  useEffect(() => { onTranscriptChange?.(transcript); }, [transcript, onTranscriptChange]);

  if (!isSupported) {
    return (
      <div className="p-6 text-center bg-bg-card rounded-xl border border-border">
        <p className="text-text-muted">Voice recording not supported in this browser. Please type your answer below.</p>
        <textarea
          className="mt-4 w-full h-40 p-4 bg-bg-surface border border-border rounded-lg text-sm resize-none focus:outline-none focus:border-primary"
          placeholder="Type your answer here..."
          onChange={(e) => { setTranscript(e.target.value); onTranscriptChange?.(e.target.value); }}
        />
      </div>
    );
  }

  return (
    <div className="bg-bg-card rounded-xl border border-border p-6">
      <div className="flex flex-col items-center gap-4">
        <motion.button
          onClick={isRecording ? stopRecording : startRecording}
          className={`w-20 h-20 rounded-full flex items-center justify-center text-3xl transition-colors ${isRecording ? 'bg-danger shadow-[0_0_30px_rgba(239,68,68,0.4)]' : 'bg-primary hover:bg-primary-hover'}`}
          animate={isRecording ? { scale: [1, 1.1, 1] } : {}}
          transition={isRecording ? { duration: 1.5, repeat: Infinity } : {}}
          whileTap={{ scale: 0.9 }}
        >
          {isRecording ? '⏹' : '🎙️'}
        </motion.button>
        <p className="text-sm text-text-muted">{isRecording ? 'Recording... Click to stop' : 'Click to start recording'}</p>
      </div>

      <div className="mt-4 p-4 bg-bg-surface rounded-lg min-h-[120px] border border-border">
        <p className="text-xs text-text-muted mb-2">Transcript:</p>
        <p className="text-sm text-text-primary whitespace-pre-wrap">{transcript || 'Your speech will appear here...'}</p>
        {isRecording && <span className="inline-block w-0.5 h-4 bg-primary animate-pulse ml-0.5" />}
      </div>
    </div>
  );
}

import { motion } from 'framer-motion';
import { COMPANY_TYPES } from '../../lib/constants.js';
import { cardVariants } from '../../animations/variants.js';

export default function CompanySelector({ selected, onSelect }) {
  return (
    <div className="grid grid-cols-2 sm:grid-cols-3 gap-4">
      {COMPANY_TYPES.map((co) => (
        <motion.button
          key={co.value}
          variants={cardVariants}
          initial="initial"
          animate="animate"
          whileHover="hover"
          whileTap="tap"
          onClick={() => onSelect(co.value)}
          className={`p-5 rounded-xl border-2 text-center transition-all ${selected === co.value ? 'border-primary bg-primary/10 shadow-glow' : 'border-border bg-bg-card hover:border-border-light'}`}
        >
          <div className="text-3xl mb-2">{co.icon}</div>
          <h3 className="font-semibold text-sm">{co.label}</h3>
          <p className="text-xs text-text-muted mt-1">{co.description}</p>
        </motion.button>
      ))}
    </div>
  );
}

import { motion } from 'framer-motion';
import { SDE_LEVELS } from '../../lib/constants.js';
import { cardVariants } from '../../animations/variants.js';

export default function LevelSelector({ selected, onSelect }) {
  return (
    <div className="grid grid-cols-1 sm:grid-cols-2 gap-4">
      {SDE_LEVELS.map((level) => (
        <motion.button
          key={level.value}
          variants={cardVariants}
          initial="initial"
          animate="animate"
          whileHover="hover"
          whileTap="tap"
          onClick={() => onSelect(level.value)}
          className={`p-6 rounded-xl border-2 text-left transition-all ${selected === level.value ? 'border-primary bg-primary/10 shadow-glow' : 'border-border bg-bg-card hover:border-border-light'}`}
        >
          <div className="flex items-center gap-3">
            <div className="w-10 h-10 rounded-lg flex items-center justify-center text-lg font-bold" style={{ backgroundColor: `${level.color}20`, color: level.color }}>{level.label.split('-')[1]}</div>
            <div>
              <h3 className="font-semibold text-lg">{level.label}</h3>
              <p className="text-xs text-text-muted">{level.description}</p>
            </div>
          </div>
        </motion.button>
      ))}
    </div>
  );
}

import { motion } from 'framer-motion';
import { DEV_ROLES } from '../../lib/constants.js';
import { cardVariants } from '../../animations/variants.js';

export default function RoleSelector({ selected, onSelect }) {
  return (
    <div className="grid grid-cols-2 sm:grid-cols-3 gap-4">
      {DEV_ROLES.map((role) => (
        <motion.button
          key={role.value}
          variants={cardVariants}
          initial="initial"
          animate="animate"
          whileHover="hover"
          whileTap="tap"
          onClick={() => onSelect(role.value)}
          className={`p-5 rounded-xl border-2 text-center transition-all ${selected === role.value ? 'border-primary bg-primary/10 shadow-glow' : 'border-border bg-bg-card hover:border-border-light'}`}
        >
          <div className="text-3xl mb-2">{role.icon}</div>
          <h3 className="font-semibold text-sm">{role.label}</h3>
          <p className="text-xs text-text-muted mt-1">{role.description}</p>
        </motion.button>
      ))}
    </div>
  );
}

