/**
 * useSocket — manages Socket.io connection lifecycle.
 */
import { useEffect, useRef, useCallback } from 'react';
import { getSocket, disconnectSocket } from '../lib/socket.js';
import { useUserStore } from '../store/userStore.js';

export function useSocket() {
  const socketRef = useRef(null);
  const { isAuthenticated } = useUserStore();

  useEffect(() => {
    if (isAuthenticated) {
      socketRef.current = getSocket();
    }
    return () => {
      // Don't disconnect on unmount if still authenticated
    };
  }, [isAuthenticated]);

  const emit = useCallback((event, data) => {
    socketRef.current?.emit(event, data);
  }, []);

  const on = useCallback((event, callback) => {
    socketRef.current?.on(event, callback);
    return () => socketRef.current?.off(event, callback);
  }, []);

  const off = useCallback((event, callback) => {
    socketRef.current?.off(event, callback);
  }, []);

  return { socket: socketRef.current, emit, on, off, disconnect: disconnectSocket };
}

/**
 * useVoice — Web Speech API hook for voice-to-text input.
 */
import { useState, useCallback, useRef } from 'react';

export function useVoice() {
  const [isRecording, setIsRecording] = useState(false);
  const [transcript, setTranscript] = useState('');
  const [isSupported] = useState(() => 'webkitSpeechRecognition' in window || 'SpeechRecognition' in window);
  const recognitionRef = useRef(null);

  const startRecording = useCallback(() => {
    if (!isSupported) return;

    const SpeechRecognition = window.SpeechRecognition || window.webkitSpeechRecognition;
    const recognition = new SpeechRecognition();

    recognition.continuous = true;
    recognition.interimResults = true;
    recognition.lang = 'en-US';

    recognition.onstart = () => setIsRecording(true);
    recognition.onend = () => setIsRecording(false);

    recognition.onresult = (event) => {
      let finalTranscript = '';
      let interimTranscript = '';

      for (let i = event.resultIndex; i < event.results.length; i++) {
        const result = event.results[i];
        if (result.isFinal) {
          finalTranscript += result[0].transcript + ' ';
        } else {
          interimTranscript += result[0].transcript;
        }
      }

      setTranscript((prev) => prev + finalTranscript);
    };

    recognition.onerror = (event) => {
      console.error('Speech recognition error:', event.error);
      setIsRecording(false);
    };

    recognitionRef.current = recognition;
    recognition.start();
  }, [isSupported]);

  const stopRecording = useCallback(() => {
    recognitionRef.current?.stop();
    setIsRecording(false);
  }, []);

  const resetTranscript = useCallback(() => {
    setTranscript('');
  }, []);

  return {
    isRecording,
    transcript,
    isSupported,
    startRecording,
    stopRecording,
    resetTranscript,
    setTranscript,
  };
}

import { Link } from 'react-router-dom';
import { motion } from 'framer-motion';
import { useDashboard } from '../queries/user.queries.js';
import { useAnalytics } from '../queries/user.queries.js';
import ScoreRadar from '../components/dashboard/ScoreRadar.jsx';
import ProgressChart from '../components/dashboard/ProgressChart.jsx';
import WeakAreaCard from '../components/dashboard/WeakAreaCard.jsx';
import SessionHistory from '../components/dashboard/SessionHistory.jsx';
import Loader from '../components/common/Loader.jsx';
import { pageVariants, staggerContainer, staggerItem } from '../animations/variants.js';
import { formatScore } from '../lib/utils.js';

const statCards = [
  { key: 'totalSessions', label: 'Total Sessions', icon: '📋' },
  { key: 'completedSessions', label: 'Completed', icon: '✅' },
  { key: 'averageScore', label: 'Avg Score', icon: '📊', format: (v) => v !== null ? Math.round(v) : '—' },
  { key: 'currentStreak', label: 'Streak', icon: '🔥', suffix: ' days' },
];

export default function Dashboard() {
  const { data: dashboard, isLoading: dLoading } = useDashboard();
  const { data: analytics, isLoading: aLoading } = useAnalytics();

  if (dLoading) return <Loader fullScreen text="Loading dashboard..." />;

  const stats = dashboard?.stats || {};

  return (
    <motion.div variants={pageVariants} initial="initial" animate="animate" exit="exit" className="min-h-screen pt-24 pb-12 px-4">
      <div className="max-w-6xl mx-auto">
        <div className="flex items-center justify-between mb-8">
          <div>
            <h1 className="text-2xl font-bold">Dashboard</h1>
            <p className="text-sm text-text-muted">Track your interview performance</p>
          </div>
          <Link to="/setup" className="px-6 py-2.5 bg-primary hover:bg-primary-hover text-white rounded-lg text-sm font-medium transition-colors btn-glow">
            New Interview →
          </Link>
        </div>

        <motion.div variants={staggerContainer} initial="initial" animate="animate" className="grid grid-cols-2 lg:grid-cols-4 gap-4 mb-8">
          {statCards.map((card) => (
            <motion.div key={card.key} variants={staggerItem} className="bg-bg-card rounded-xl border border-border p-4">
              <div className="flex items-center gap-2 mb-2">
                <span className="text-lg">{card.icon}</span>
                <span className="text-xs text-text-muted">{card.label}</span>
              </div>
              <p className="text-2xl font-bold">
                {card.format ? card.format(stats[card.key]) : (stats[card.key] || 0)}
                {card.suffix && stats[card.key] ? card.suffix : ''}
              </p>
            </motion.div>
          ))}
        </motion.div>

        <div className="grid grid-cols-1 lg:grid-cols-3 gap-6 mb-8">
          <div className="lg:col-span-2">
            <ProgressChart sessions={analytics?.trends || []} />
          </div>
          <ScoreRadar data={analytics?.profile || {}} />
        </div>

        <div className="grid grid-cols-1 md:grid-cols-2 gap-6 mb-8">
          <WeakAreaCard areas={dashboard?.weakAreas || []} type="weak" />
          <WeakAreaCard areas={dashboard?.strongAreas || []} type="strong" />
        </div>

        <div className="bg-bg-card rounded-xl border border-border p-6">
          <h2 className="text-lg font-semibold mb-4">Recent Sessions</h2>
          <SessionHistory sessions={dashboard?.recentSessions || []} />
        </div>
      </div>
    </motion.div>
  );
}

