import { useParams } from 'react-router-dom';
import { Link } from 'react-router-dom';
import { motion } from 'framer-motion';
import { useResults } from '../queries/interview.queries.js';
import { Radar, RadarChart, PolarGrid, PolarAngleAxis, ResponsiveContainer } from 'recharts';
import Loader from '../components/common/Loader.jsx';
import { ROUND_LABELS } from '../lib/constants.js';
import { getScoreColor, formatScore } from '../lib/utils.js';
import { pageVariants, staggerContainer, staggerItem, scaleBounce } from '../animations/variants.js';
import { useState, useEffect } from 'react';

function CountUp({ end, duration = 1500 }) {
  const [count, setCount] = useState(0);
  useEffect(() => {
    let start = 0;
    const step = end / (duration / 16);
    const timer = setInterval(() => {
      start += step;
      if (start >= end) { setCount(Math.round(end)); clearInterval(timer); }
      else setCount(Math.round(start));
    }, 16);
    return () => clearInterval(timer);
  }, [end, duration]);
  return count;
}

export default function Results() {
  const { sessionId } = useParams();
  const { data: session, isLoading } = useResults(sessionId);

  if (isLoading) return <Loader fullScreen text="Loading results..." />;
  if (!session) return <div className="min-h-screen flex items-center justify-center text-text-muted">Session not found</div>;

  const score = session.finalScore || 0;
  const color = getScoreColor(score);
  const radarData = session.rounds?.map(r => ({ subject: ROUND_LABELS[r.type] || r.type, score: r.score || 0 })) || [];

  return (
    <motion.div variants={pageVariants} initial="initial" animate="animate" exit="exit" className="min-h-screen pt-24 pb-12 px-4">
      {score > 70 && (
        <div className="fixed inset-0 pointer-events-none z-40">
          {Array.from({ length: 30 }).map((_, i) => (
            <motion.div key={i} className="absolute w-2 h-2 rounded-full" style={{ left: `${Math.random() * 100}%`, background: ['#6366F1', '#10B981', '#F59E0B', '#A78BFA', '#F87171'][i % 5] }} initial={{ top: '-5%', opacity: 1 }} animate={{ top: '105%', opacity: 0, rotate: Math.random() * 360 }} transition={{ duration: 2 + Math.random() * 2, delay: Math.random() * 1.5, ease: 'easeOut' }} />
          ))}
        </div>
      )}

      <div className="max-w-4xl mx-auto">
        <motion.div variants={scaleBounce} initial="initial" animate="animate" className="text-center mb-12">
          <h1 className="text-2xl font-bold mb-6">Interview Complete! 🎉</h1>
          <div className="inline-flex flex-col items-center p-8 bg-bg-card rounded-2xl border border-border">
            <span className="text-7xl font-bold" style={{ color }}><CountUp end={score} /></span>
            <span className="text-lg text-text-muted mt-1">/ 100</span>
            {session.percentile && <p className="text-sm text-text-secondary mt-3">Better than <strong>{session.percentile}%</strong> of candidates</p>}
          </div>
        </motion.div>

        {radarData.length > 0 && (
          <div className="bg-bg-card rounded-xl border border-border p-6 mb-8">
            <h2 className="text-lg font-semibold mb-4">Performance Breakdown</h2>
            <ResponsiveContainer width="100%" height={280}>
              <RadarChart data={radarData}>
                <PolarGrid stroke="var(--color-border)" />
                <PolarAngleAxis dataKey="subject" tick={{ fill: 'var(--color-text-muted)', fontSize: 11 }} />
                <Radar dataKey="score" stroke="var(--color-primary)" fill="var(--color-primary)" fillOpacity={0.2} strokeWidth={2} />
              </RadarChart>
            </ResponsiveContainer>
          </div>
        )}

        <motion.div variants={staggerContainer} initial="initial" animate="animate" className="space-y-4">
          {session.rounds?.map((round, i) => (
            <RoundResultCard key={round.id} round={round} index={i} />
          ))}
        </motion.div>

        <div className="flex items-center justify-center gap-4 mt-10 flex-wrap">
          <Link to="/setup" className="px-6 py-2.5 bg-primary hover:bg-primary-hover text-white rounded-lg transition-colors btn-glow">Try Again</Link>
          <Link to="/dashboard" className="px-6 py-2.5 border border-border rounded-lg hover:bg-bg-card transition-colors">Dashboard</Link>
        </div>
      </div>
    </motion.div>
  );
}

function RoundResultCard({ round, index }) {
  const [expanded, setExpanded] = useState(false);
  const sc = round.score || 0;
  const color = getScoreColor(sc);

  return (
    <motion.div variants={staggerItem} className="bg-bg-card rounded-xl border border-border overflow-hidden">
      <button onClick={() => setExpanded(!expanded)} className="w-full flex items-center justify-between p-4 hover:bg-bg-elevated transition-colors">
        <div className="flex items-center gap-3">
          <span className="w-8 h-8 rounded-lg bg-bg-elevated flex items-center justify-center text-sm font-bold">{round.roundNumber}</span>
          <span className="font-medium text-sm">{ROUND_LABELS[round.type] || round.type}</span>
        </div>
        <div className="flex items-center gap-3">
          <span className="text-lg font-bold" style={{ color }}>{Math.round(sc)}</span>
          <motion.span animate={{ rotate: expanded ? 180 : 0 }} className="text-text-muted">▼</motion.span>
        </div>
      </button>
      {expanded && round.questions?.map((q, qi) => (
        <div key={q.id} className="px-4 pb-4 border-t border-border">
          <div className="pt-3">
            <p className="text-xs text-text-muted mb-1">Q{qi + 1}: {q.content?.slice(0, 120)}...</p>
            {q.aiEvaluation && (
              <div className="mt-2 p-3 bg-bg-surface rounded-lg text-xs space-y-1">
                <p><strong>Score:</strong> <span style={{ color: getScoreColor(q.score || 0) }}>{q.score}/100</span></p>
                {q.aiEvaluation.verdict && <p><strong>Verdict:</strong> {q.aiEvaluation.verdict}</p>}
                {q.aiEvaluation.positiveFeedback && <p className="text-success-light">✓ {q.aiEvaluation.positiveFeedback}</p>}
              </div>
            )}
            {q.skipped && <p className="mt-2 text-xs text-warning">⏭ Skipped</p>}
          </div>
        </div>
      ))}
    </motion.div>
  );
}

import { useState } from 'react';
import { useNavigate } from 'react-router-dom';
import { motion, AnimatePresence } from 'framer-motion';
import { useCreateSession } from '../queries/interview.queries.js';
import LevelSelector from '../components/setup/LevelSelector.jsx';
import RoleSelector from '../components/setup/RoleSelector.jsx';
import CompanySelector from '../components/setup/CompanySelector.jsx';
import { pageVariants, slideRight } from '../animations/variants.js';

const STEPS = ['Level', 'Role', 'Company'];

export default function Setup() {
  const [step, setStep] = useState(0);
  const [level, setLevel] = useState('');
  const [role, setRole] = useState('');
  const [companyType, setCompanyType] = useState('');
  const createSession = useCreateSession();
  const navigate = useNavigate();

  const canProceed = step === 0 ? !!level : step === 1 ? !!role : !!companyType;

  const handleNext = () => {
    if (step < 2) { setStep(step + 1); return; }
    createSession.mutate({ level, role, companyType }, {
      onSuccess: (data) => navigate(`/interview/${data.id}`),
    });
  };

  return (
    <motion.div variants={pageVariants} initial="initial" animate="animate" exit="exit" className="min-h-screen pt-24 pb-12 px-4">
      <div className="max-w-2xl mx-auto">
        <div className="flex items-center gap-2 mb-10">
          {STEPS.map((s, i) => (
            <div key={s} className="flex items-center gap-2 flex-1">
              <div className={`w-8 h-8 rounded-full flex items-center justify-center text-xs font-bold transition-colors ${i <= step ? 'bg-primary text-white' : 'bg-bg-card text-text-muted border border-border'}`}>{i + 1}</div>
              <span className={`text-sm hidden sm:block ${i <= step ? 'text-primary' : 'text-text-muted'}`}>{s}</span>
              {i < 2 && <div className={`flex-1 h-0.5 ${i < step ? 'bg-primary' : 'bg-border'}`} />}
            </div>
          ))}
        </div>

        <AnimatePresence mode="wait">
          <motion.div key={step} variants={slideRight} initial="initial" animate="animate" exit="exit" transition={{ duration: 0.3 }}>
            <h2 className="text-2xl font-bold mb-2">
              {step === 0 && 'Select Your Experience Level'}
              {step === 1 && 'Choose Your Target Role'}
              {step === 2 && 'Pick Company Type'}
            </h2>
            <p className="text-sm text-text-muted mb-8">
              {step === 0 && 'This determines the difficulty and round structure of your interview.'}
              {step === 1 && 'Questions will be tailored to your role specialization.'}
              {step === 2 && 'Company type affects the interview format and question style.'}
            </p>

            {step === 0 && <LevelSelector selected={level} onSelect={setLevel} />}
            {step === 1 && <RoleSelector selected={role} onSelect={setRole} />}
            {step === 2 && <CompanySelector selected={companyType} onSelect={setCompanyType} />}
          </motion.div>
        </AnimatePresence>

        <div className="flex items-center justify-between mt-10">
          <button onClick={() => step > 0 && setStep(step - 1)} disabled={step === 0} className="px-6 py-2.5 text-sm border border-border rounded-lg hover:bg-bg-card transition-colors disabled:opacity-30">Back</button>
          <button onClick={handleNext} disabled={!canProceed || createSession.isPending} className="px-8 py-2.5 text-sm bg-primary hover:bg-primary-hover text-white rounded-lg font-medium transition-colors disabled:opacity-50 btn-glow">
            {createSession.isPending ? 'Creating...' : step === 2 ? 'Start Interview →' : 'Next →'}
          </button>
        </div>
      </div>
    </motion.div>
  );
}

/**
 * Auth React Query hooks.
 */
import { useMutation, useQuery, useQueryClient } from '@tanstack/react-query';
import api, { setAccessToken } from '../lib/axios.js';
import { useUserStore } from '../store/userStore.js';
import { queryKeys } from './queryKeys.js';

/** Fetch current authenticated user */
export function useMe() {
  const { setUser, clearUser, setLoading } = useUserStore();

  return useQuery({
    queryKey: queryKeys.auth.me,
    queryFn: async () => {
      const { data } = await api.get('/auth/me');
      return data.data.user;
    },
    retry: false,
    staleTime: 5 * 60 * 1000, // 5 min
    onSuccess: (user) => {
      setUser(user, null); // Token already set from login/refresh
      setLoading(false);
    },
    onError: () => {
      clearUser();
      setLoading(false);
    },
  });
}

/** Register mutation */
export function useRegister() {
  const { setUser } = useUserStore();
  const queryClient = useQueryClient();

  return useMutation({
    mutationFn: async ({ name, email, password }) => {
      const { data } = await api.post('/auth/register', { name, email, password });
      return data.data;
    },
    onSuccess: (data) => {
      setUser(data.user, data.accessToken);
      queryClient.setQueryData(queryKeys.auth.me, data.user);
    },
  });
}

/** Login mutation */
export function useLogin() {
  const { setUser } = useUserStore();
  const queryClient = useQueryClient();

  return useMutation({
    mutationFn: async ({ email, password }) => {
      const { data } = await api.post('/auth/login', { email, password });
      return data.data;
    },
    onSuccess: (data) => {
      setUser(data.user, data.accessToken);
      queryClient.setQueryData(queryKeys.auth.me, data.user);
    },
  });
}

/** Logout mutation */
export function useLogout() {
  const { clearUser } = useUserStore();
  const queryClient = useQueryClient();

  return useMutation({
    mutationFn: async () => {
      await api.post('/auth/logout');
    },
    onSettled: () => {
      clearUser();
      queryClient.clear();
    },
  });
}
